examples.code:
// WRONG — compares memory addresses:
String s1 = "hello";
String s2 = "hello";
System.out.println(s1 == s2);      // may print false!

// CORRECT — compares content:
System.out.println(s1.equals(s2)); // always true ✅
System.out.println(s1.equalsIgnoreCase("HELLO")); // true

int age = 20;
boolean hasID = true;

// AND: both conditions must be true
boolean canEnter = (age >= 18) && hasID;  // true

// OR: either condition must be true
boolean discount = (age < 12) || (age > 65); // false

// NOT: flips the boolean
boolean isMinor = !(age >= 18);  // false

// With &&: if LEFT is false, RIGHT is SKIPPED
int x = 0;
if (x != 0 && (100 / x > 5)) { // safe!
    System.out.println("ok");
}
// x != 0 is false → right side never evaluated → no ÷0 crash!

