examples.code:
int day = 3;
switch (day) {
    case 1:
        System.out.println("Monday"); break;
    case 2:
        System.out.println("Tuesday"); break;
    case 3:
        System.out.println("Wednesday"); break;
    default:
        System.out.println("Other day");
}
// Output: Wednesday

// Fall-through example:
int x = 1;
switch (x) {
    case 1: System.out.println("One");
    case 2: System.out.println("Two"); break;
    case 3: System.out.println("Three");
}
// Output: One↵Two (falls through case 2!)

// Java switch also works with Strings:
String lang = "Java";
switch (lang) {
    case "Java": System.out.println("JVM"); break;
    case "Python": System.out.println("CPython"); break;
}

int age = 20;
String status = (age >= 18) ? "adult" : "minor";
System.out.println(status); // adult

// Without ternary (4 lines → 1 line):
int a = 5, b = 8;
int max = (a > b) ? a : b;
System.out.println(max); // 8

// Ternary in println:
int score = 75;
System.out.println(score >= 60 ? "Pass" : "Fail"); // Pass

// READABLE: simple condition
String msg = (x > 0) ? "positive" : "non-positive";

// CONFUSING: nested ternary (avoid!)
String g = (s>=90) ? "A" : (s>=80) ? "B" : "C"; // hard to read

// BETTER: use if/else for complex logic

