examples.code:
int x = 10;  // lives in method scope

if (x > 5) {
    int bonus = 50;  // only lives inside this if block
    System.out.println(x + bonus);  // 60 ✅
}

// System.out.println(bonus);  // ❌ COMPILE ERROR!
// bonus doesn't exist outside the if block

# Python — if block doesn't create scope:
if True:
    msg = 'hello'
print(msg)  # works! 'hello' still accessible ✅

// Java — if block CREATES scope:
if (true) {
    String msg = "hello";
}
// System.out.println(msg);  // ERROR! msg is gone ❌

int score = 100;

if (score > 50) {
    // This int score shadows the outer one:
    // (Note: Java doesn't allow this in some versions)
    // Better practice — use a different name:
    int bonusScore = score + 50;
    System.out.println(bonusScore);  // 150
}

System.out.println(score);  // 100 (outer unchanged)

